/**
 * @summary Create a new seva drive with image upload (admin only)
 */
export const getCreateDriveUrl = () => {
  return `/api/drives/create`;
};

export const createDrive = async (
  createDriveBody: CreateDriveBody,
  options?: RequestInit,
): Promise<SevaDrive> => {
  const formData = new FormData();
  formData.append(`title`, createDriveBody.title);
  formData.append(`description`, createDriveBody.description);
  formData.append(`location`, createDriveBody.location);
  formData.append(`date`, createDriveBody.date);

  return customFetch<SevaDrive>(getCreateDriveUrl(), {
    ...options,
    method: "POST",
    body: formData,
  });
};

